1303       if (replaceInInstruction(TrueVal, CmpLHS, CmpRHS))
1304         return &Sel;
1305   }
1306   if (TrueVal != CmpRHS &&
1307       isGuaranteedNotToBeUndefOrPoison(CmpLHS, SQ.AC, &Sel, &DT))
